@namespace Lumeo
@implements IDisposable

<div id="@EffectiveId"
     class="@CssClass"
     role="@Role"
     aria-live="@AriaLive"
     aria-atomic="true"
     data-index="@(StackIndex?.ToString())"
     @onmouseenter="OnMouseEnter"
     @onmouseleave="OnMouseLeave"
     @onfocusin="OnFocusIn"
     @onfocusout="OnFocusOut"
     @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public ToastVariant Variant { get; set; } = ToastVariant.Default;

    /// <summary>
    /// Stable DOM id for the toast root. The provider sets this so it can
    /// register the touch swipe-to-dismiss gesture against this element via
    /// <see cref="Lumeo.Services.IComponentInteropService.RegisterToastSwipe"/>.
    /// When omitted (a standalone <c>&lt;Toast&gt;</c> rendered outside
    /// ToastProvider, e.g. a static variant preview), a generated id is used
    /// instead.
    /// </summary>
    [Parameter] public string? Id { get; set; }

    /// <summary>
    /// Stack position within its position group, 0 = newest/front. Set by
    /// ToastProvider when <c>StackToasts</c> is enabled; null renders no
    /// <c>data-index</c> attribute at all (legacy list, no stacking CSS
    /// applies). See lumeo.css's "Toast stacking" section.
    /// </summary>
    [Parameter] public int? StackIndex { get; set; }

    /// <summary>
    /// True while ToastProvider is playing this toast's exit animation
    /// (<c>animate-toast-out</c>) ahead of unmounting it. Owned here (rather
    /// than folded into <see cref="Class"/> by the caller) so
    /// <see cref="CssClass"/> can also strip the entrance class the instant
    /// this flips true — a dismiss that lands mid-entrance must play the exit
    /// cleanly, not fight a still-parked <c>animate-toast-in</c>.
    /// </summary>
    [Parameter] public bool Leaving { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter] public EventCallback OnMouseEnter { get; set; }
    [Parameter] public EventCallback OnMouseLeave { get; set; }
    [Parameter] public EventCallback OnFocusIn { get; set; }
    [Parameter] public EventCallback OnFocusOut { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Generated inline (not Lumeo.Internal.LumeoIds — that helper is `internal` to the Lumeo
    // assembly, so a vendored copy of this file compiled inside a consumer app under the default
    // NuGet-backed `lumeo add toast` path can't resolve it). Same "{prefix}-{guidN}" convention.
    private readonly string _generatedId = $"toast-{Guid.NewGuid():N}";
    private string EffectiveId => Id ?? _generatedId;

    // True while `animate-toast-in` still governs this element. Starts true for
    // every newly-mounted toast (one Toast instance per toast id — keyed by
    // ToastProvider — so this field is set exactly once per toast's lifetime)
    // and flips false the moment the entrance finishes: `animate-toast-in` uses
    // `animation-fill-mode: both`, so once it settles it permanently pins
    // opacity:1/transform:none on the element — a running OR filled keyframe
    // always wins over a plain declared value for the same property regardless
    // of selector specificity, so that held fill silently overrides the
    // "Toast stacking" transforms (lumeo.css) the moment this toast is no
    // longer at data-index="0", and on dismiss fights `animate-toast-out`
    // (equal specificity, `animate-toast-in` declared later). Mirrors the
    // institutional "never leave a filled animation parked on an element"
    // lesson (Radix-Presence, 4.1.0-preview.15): once entered, the toast
    // carries NO animation, so the stacking transform applies immediately and
    // a later dismiss's `animate-toast-out` isn't fighting a stuck class.
    //
    // Cleanup is driven PURELY by a local timer (EnterFallbackMs below), NOT a
    // JS-side animationend callback. PR #357 round-4 (P1): an earlier revision
    // wired this up via Interop.AttachToastEnterEnd/IToastEnterCallback for
    // frame-exact precision, but BOTH are Lumeo interop surface added in this
    // same unreleased change — a vendored copy of this file compiled in a
    // consumer app whose referenced Lumeo package predates that addition
    // (any currently-published version, since it ships only once THIS PR
    // itself is released) fails to compile: `IToastEnterCallback` doesn't
    // exist as a type yet, and `AttachToastEnterEnd` isn't a member of
    // `IComponentInteropService` yet either. Default interface members only
    // protect IMPLEMENTERS of an evolving interface, not CALLERS reading a
    // member the referenced assembly's metadata simply doesn't declare — so
    // there is no compile-safe way to call a brand-new interop member from
    // source that gets vendored verbatim into arbitrary consumer projects.
    // A plain timer has zero Lumeo-surface dependency (see EnterFallbackTimer
    // below), so it's the only mechanism this file can use unconditionally.
    // Also a Razor `@onanimationend` handler was considered and rejected
    // (this codebase already tried that for the Sheet/Drawer slide-in case —
    // see the rc.22 note in components.js/lumeo.css — and dropped it):
    // Blazor's onanimationend EventArgs carry no AnimationName, so a handler
    // bound in Razor can't tell the toast's own entrance apart from a
    // one-shot animation on arbitrary CustomContent (a Badge, a spinner, ...)
    // bubbling out of the toast and would fire early.
    private bool _entering = true;
    // A local one-shot timer, NOT Lumeo.Services.DelayedDispatch — that helper is `internal` to
    // the Lumeo assembly, so a vendored copy of this file compiled inside a consumer app under the
    // default NuGet-backed `lumeo add toast` path can't resolve it. This duplicates just the
    // single-pending-callback + cancel/dispose behaviour Toast.razor actually needs.
    private readonly EnterFallbackTimer _enterFallback = new();

    // Sits comfortably above the CSS entrance duration (toast-in is 0.3s, or
    // 1ms under prefers-reduced-motion — still a real animation) so a normal
    // entrance has visually settled well before this fires; under
    // prefers-reduced-motion the stacking transform simply lags this fixed
    // window instead of the (near-instant) animationend — a bounded, minor
    // cosmetic cost worth paying for compiling in every supported consumer
    // project unconditionally (see the field comment above).
    private const int EnterFallbackMs = 350;

    protected override void OnParametersSet()
    {
        // Dismissed while still entering (rapid show+dismiss): strip the
        // entrance class immediately instead of waiting for the fallback
        // timer — OnParametersSet already knows Leaving flipped, no reason
        // to sit on the remaining window for something already decided.
        if (Leaving && _entering)
        {
            FinishEntering();
        }
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender && _entering)
        {
            _enterFallback.Schedule(EnterFallbackMs, () => InvokeAsync(FinishEntering));
        }
    }

    private void FinishEntering()
    {
        if (!_entering) return;
        _entering = false;
        _enterFallback.Cancel();
        StateHasChanged();
    }

    public void Dispose()
    {
        _enterFallback.Dispose();
    }

    private string CssClass => Lumeo.Cx.Merge(
        "group pointer-events-auto relative flex w-full items-center justify-between space-x-2 overflow-hidden rounded-md border border-border/50 p-4 pe-11 sm:pe-6 shadow-lg",
        Leaving ? "animate-toast-out" : Lumeo.Cx.When(_entering, "animate-toast-in"),
        VariantClasses, Class);

    // Destructive variant uses role="alert" + aria-live="assertive" so screen readers
    // interrupt with errors; informational variants use role="status" + aria-live="polite"
    // so they're announced without interrupting the user. Matches Radix Toast / sonner.
    private string Role => Variant == ToastVariant.Destructive ? "alert" : "status";
    private string AriaLive => Variant == ToastVariant.Destructive ? "assertive" : "polite";

    private string VariantClasses => Variant switch
    {
        ToastVariant.Default => "bg-card text-foreground",
        ToastVariant.Success => "border-success/50 bg-success-light text-success-text",
        ToastVariant.Destructive => "border-destructive/50 bg-destructive-light text-destructive-text",
        ToastVariant.Warning => "border-warning/50 bg-warning-light text-warning-text",
        ToastVariant.Info => "border-info/50 bg-info-light text-info-text",
        _ => "bg-card text-foreground"
    };

    // Minimal local stand-in for Lumeo.Services.DelayedDispatch: a single pending one-shot
    // callback that a later Schedule() replaces and Cancel()/Dispose() can pre-empt. Deliberately
    // NOT the shared internal helper (see the _enterFallback field comment) — a vendored copy of
    // this file must compile standalone in a consumer app with no access to Lumeo's internals.
    private sealed class EnterFallbackTimer : IDisposable
    {
        private System.Threading.Timer? _timer;
        private int _sequence;

        public void Schedule(int delayMs, Func<Task> action)
        {
            _timer?.Dispose();
            var seq = ++_sequence;
            _timer = new System.Threading.Timer(_ =>
            {
                if (seq != _sequence) return;
                _ = RunSafe(action);
            }, null, delayMs, System.Threading.Timeout.Infinite);
        }

        public void Cancel()
        {
            ++_sequence;
            _timer?.Dispose();
            _timer = null;
        }

        // PR #357 round-6 finding 5: must invalidate via Cancel() (bumps `_sequence`), NOT just
        // dispose the timer. `System.Threading.Timer.Dispose()` does not wait for/cancel a
        // callback that has ALREADY been queued to the thread pool (unmounting mid-fire is exactly
        // the case here — a toast can be torn down for reasons other than entering `Leaving`, e.g.
        // navigating away while a fresh toast is still entering). That already-queued callback can
        // still run after this returns, see `seq != _sequence` pass (nothing bumped it), and call
        // `InvokeAsync(FinishEntering)` on a disposed component. Same idiom as
        // ToastViewport's `_focusOutSequence` guard (round-5).
        public void Dispose() => Cancel();

        private static async Task RunSafe(Func<Task> action)
        {
            try { await action(); }
            catch (ObjectDisposedException) { }
        }
    }
}

@namespace Lumeo

<button type="button" class="@CssClass" @onclick="OnClick" @attributes="AdditionalAttributes">
    @Label
</button>

@code {
    [Parameter] public string? Label { get; set; }
    [Parameter] public EventCallback OnClick { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Lumeo.Cx.Merge("inline-flex h-8 shrink-0 items-center justify-center rounded-md border border-transparent bg-primary px-3 text-sm font-medium text-primary-foreground transition-colors hover:opacity-90 focus:outline-none focus:ring-1 focus:ring-ring", Class);
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<button type="button" class="@CssClass" aria-label="@EffectiveAriaLabel"
        @onclick="OnClose"
        @attributes="AdditionalAttributes">
    <Lumeo.SvgGlyph Svg="@(Lumeo.LumeoIcons.X)" class="h-4 w-4" />
    <span class="sr-only">@EffectiveAriaLabel</span>
</button>

@code {
    [Parameter] public EventCallback OnClose { get; set; }
    /// <summary>Accessible name for the close button. Override for i18n.</summary>
    [Parameter] public string? AriaLabel { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string EffectiveAriaLabel => AriaLabel ?? L["Toast.Close"];

    // Position: 4px inset on mobile so the 44px focus ring doesn't clip the toast border.
    // Size: 44px on touch (WCAG 2.5.5) → 24px on desktop with hover-reveal pattern.
    // Affordance: text-foreground/50 → hover/focus text-foreground + subtle bg → clear interactive state on every variant.
    // Focus ring: ring-current so it inherits text color, staying visible on coloured variants (Destructive, Success, Warning, Info).
    private string CssClass => Lumeo.Cx.Merge("group/close absolute end-1 top-1 inline-flex items-center justify-center rounded-md h-11 w-11 sm:end-1 sm:top-1 sm:h-6 sm:w-6 text-foreground/50 hover:text-foreground hover:bg-foreground/10 focus-visible:bg-foreground/10 focus-visible:text-foreground opacity-100 sm:opacity-0 transition-[opacity,color,background-color] sm:group-hover:opacity-100 focus-visible:opacity-100 focus:outline-none focus-visible:ring-2 focus-visible:ring-current focus-visible:ring-offset-1 focus-visible:ring-offset-transparent", Class);
}

@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Lumeo.Cx.Merge("text-xs opacity-90", Class);
}

@namespace Lumeo
@using Lumeo.Services
@implements IAsyncDisposable

@*  rc.42 — Per-toast Position routing.
    Up to rc.41 we mounted a single <ToastViewport Position="Position"> and every
    toast landed there, silently ignoring ToastOptions.Position (the per-call
    override added in rc.37). Now we route each toast to a viewport keyed by its
    effective position (options.Position ?? provider Position). The provider's
    own default Position viewport is ALWAYS rendered (even when empty) so
    consumers that rely on the viewport DOM being present — for styling, layout
    measurement, or test assertions on position classes — still see it. Extra
    viewports are only spawned when a toast actually targets a different
    position. *@
@{
    var positionsToRender = _toasts
        .Select(t => ResolvePosition(t.Options.Position))
        .Distinct()
        .ToList();
    if (!positionsToRender.Contains(Position))
    {
        positionsToRender.Insert(0, Position);
    }
}
@foreach (var pos in positionsToRender)
{
    var group = _toasts.Where(t => ResolvePosition(t.Options.Position) == pos).ToList();
    var groupCount = group.Count;
    <ToastViewport Position="@pos" StackToasts="@StackToasts" ToastCount="@groupCount" @key="@pos">
        @{
            // Live-only count: how many toasts in this group are NOT mid-exit. Live toasts are
            // ranked among THEMSELVES (below), never against the raw group — see the comment on
            // liveCursor for why.
            var liveCount = group.Count(t => !(t.Leaving && t.FrozenIndex.HasValue));
            var liveCursor = 0;
            // PR #357 round-4 (P2): whether a Leaving toast is CURRENTLY frozen at index 0 (the
            // exact "front toast dismissed while another remains" case — see the stackIndex
            // comment below). Computed ONCE per group/render, not per-toast, since it gates every
            // live toast's ranking identically.
            var frontFrozen = group.Any(t => t.Leaving && t.FrozenIndex == 0);
        }
        @foreach (var toast in group)
        {
            // Newest (last appended = last in group, since _toasts is oldest-first)
            // gets stack index 0 (front). See lumeo.css's "Toast stacking" section.
            //
            // A toast already Leaving keeps the index it had the INSTANT its exit
            // started (FrozenIndex, stamped in RemoveWithExitAsync) instead of the
            // freshly recomputed one. Without this, a toast that started leaving
            // hidden at depth>=3 gets PROMOTED to a visible index (e.g. 2) the
            // moment a newer toast ahead of it is dismissed/times out mid-exit —
            // `.animate-toast-out`'s `from { opacity: 1 }` keyframe then wins over
            // the (now non-matching) `visibility:hidden` depth rule and the
            // previously-invisible toast flashes visible for the rest of its exit.
            // Freezing decouples a toast's OWN departure from the stack
            // reshuffling still happening around it — matches the fact its
            // position/visibility contract was already fixed the moment dismissal
            // began.
            //
            // LIVE toasts are ranked among the live SUBSET only (liveCount/liveCursor), NOT
            // `groupCount`/a shared cursor over every toast including frozen ones. PR #357
            // round-3: overlapping exits (front toast leaves, then an older sibling ALSO starts
            // leaving before the front's 220ms timer elapses) leave a frozen, no-longer-current
            // index parked on that older sibling. Once the front toast actually unmounts, ranking
            // live toasts against the shrunk `groupCount` while the frozen sibling keeps its STALE
            // (pre-shrink) value collides two toasts onto the SAME index and, in the worst case
            // (only one live toast left), leaves NO toast at index 0 at all — the only index the
            // collapsed-stack CSS keeps in normal flow, so the viewport can collapse to nothing
            // until the frozen sibling's own exit finishes. Ranking live toasts purely by their
            // OWN newest-first order guarantees the frontmost LIVE toast always claims index 0,
            // completely independent of however many stale frozen values sit alongside it.
            //
            // PR #357 round-4 (P2): that guarantee ("some live toast always gets index 0") can
            // itself collide with a FROZEN index 0 — the ordinary case of the front toast being
            // dismissed while an older sibling remains live. lumeo.css only keeps `data-index="0"`
            // in normal flow (position: relative); every other index is position: absolute. Two
            // elements both claiming index 0 therefore both sit in flow for the Leaving toast's
            // 220ms exit, expanding the collapsed stack into two rows. `frontFrozen` (computed
            // above) reserves index 0 for that frozen occupant and shifts every LIVE toast's rank
            // up by one — the next toast in line visually sits at (now-hidden) depth 1 instead,
            // and slides into index 0 on its own once the leaving front actually unmounts and a
            // fresh render recomputes indices with no frozen occupant left.
            var stackIndex = StackToasts
                ? (toast.Leaving && toast.FrozenIndex.HasValue
                    ? toast.FrozenIndex
                    : liveCount - 1 - liveCursor + (frontFrozen ? 1 : 0))
                : (int?)null;
            if (!(toast.Leaving && toast.FrozenIndex.HasValue)) liveCursor++;
            <Toast Variant="@toast.Options.Variant"
                   Id="@ToastElementId(toast.Id)"
                   Class="@toast.Options.Class"
                   Leaving="@toast.Leaving"
                   StackIndex="@stackIndex"
                   OnMouseEnter="@(() => PauseTimer(toast.Id))"
                   OnMouseLeave="@(() => ResumeTimer(toast.Id))"
                   OnFocusIn="@(() => PauseTimer(toast.Id))"
                   OnFocusOut="@(() => ResumeTimer(toast.Id))"
                   @key="@toast.Id">
                @if (toast.Options.CustomContent is not null)
                {
                    @toast.Options.CustomContent
                }
                else
                {
                    <div class="grid gap-1">
                        <ToastTitle>@toast.Options.Title</ToastTitle>
                        @if (toast.Options.Description is not null)
                        {
                            <ToastDescription>@toast.Options.Description</ToastDescription>
                        }
                        @if (toast.Options.ActionLabel is not null)
                        {
                            <ToastAction OnClick="@(() => InvokeAction(toast))" Label="@toast.Options.ActionLabel" />
                        }
                    </div>
                }
                @if (toast.Options.Dismissible)
                {
                    <ToastClose OnClose="@(() => Remove(toast.Id))" />
                }
            </Toast>
        }
    </ToastViewport>
}


@inject ToastService ToastService
@inject IComponentInteropService Interop

@code {
    private readonly List<ToastItem> _toasts = new();
    private readonly Dictionary<string, CancellationTokenSource> _timers = new();
    // Toast ids that currently have the JS swipe-to-dismiss gesture attached
    // to their DOM element, so we register once per toast and unregister on
    // removal/dispose. Maps toast id -> element id passed to the JS layer.
    private readonly Dictionary<string, string> _swipeRegistered = new();
    private readonly Dictionary<string, CancellationTokenSource> _exitTimers = new();
    // Per-toast timer bookkeeping for pause-on-hover/focus:
    //   _timerStart    = wall-clock time the current Task.Delay started
    //   _timerRemaining = ms left at the moment the timer was last (re)started
    //   _paused        = true while the user is hovering / focused inside
    // On pause we cancel the running delay and subtract elapsed from remaining.
    // On resume we start a fresh delay with the leftover. Matches Radix Toast / sonner.
    private readonly Dictionary<string, DateTime> _timerStart = new();
    private readonly Dictionary<string, int> _timerRemaining = new();
    private readonly HashSet<string> _paused = new();
    // Every non-persistent toast that isn't mounted yet — whether it's waiting on room right now
    // or an eviction that hasn't finished — sits here. FIFO by arrival order, same as sonner's
    // overflow queue. PR #357 round-6: ReconcileGroup (below) is the ONLY method that ever dequeues
    // and mounts from this; see the ADMISSION MODEL comment on ReconcileGroup for why that's load-
    // bearing, not incidental.
    private readonly Queue<ToastMessage> _pendingQueue = new();

    // PR #357 round-6: deliberately NO per-position lock/semaphore here. An earlier version of this
    // fix serialized every mutation+reconciliation for a position behind a mutex — safe, but wrong
    // for a different reason: eviction ALWAYS waits out the real ~220ms exit animation
    // (RemoveWithExitAsync), so a mutex-serialized burst of N overflowing toasts took N*~220ms
    // wall-clock to settle instead of ~220ms (every eviction's animation overlapping, as they do
    // without a lock) — a real, user-visible regression (a 100-toast spam burst went from settling
    // in ~220ms to over 20 seconds), not just a slower test.
    // <para>
    // No lock is needed because single-threaded cooperative scheduling (Blazor's renderer
    // synchronization context — nothing here is EVER running on two threads at once) already makes
    // "mutate `_toasts`/`_pendingQueue`, then immediately evaluate + act on that fresh state" atomic
    // for any stretch of code with no `await` in between. Every mutation site below chains straight
    // into its OWN call to <see cref="ReconcileGroup"/> with no intervening `StateHasChanged()` or
    // other yield, so the very first render anyone observes after a mutation already reflects
    // whatever correction that mutation required — evictions overlap freely (each candidate is
    // chosen via `!t.Leaving`, so two concurrent passes for the same position can never pick the
    // same toast twice), and admission only ever happens through ReconcileGroup's own fresh
    // FIFO-dequeue check (TryAdmit never mounts its own message directly), so "who gets the next
    // freed slot" is decided once, for real, at the moment a slot is actually available — never by
    // a caller that assumed its OWN eviction would be the one to free it (that assumption was
    // finding 1's original bug).
    // </para>

    [Parameter] public ToastViewport.ToastPosition Position { get; set; } = ToastViewport.ToastPosition.BottomRight;
    [Parameter] public int DefaultDuration { get; set; } = 5000;

    /// <summary>
    /// Maximum number of NON-PERSISTENT toasts (resolved <c>Duration != 0</c> — see
    /// <see cref="IsPersistent"/>) mounted at once per position group; overflow queues FIFO (see
    /// <see cref="_pendingQueue"/>) and drains as slots free up. Non-positive values are clamped up
    /// to 1 — there's no "unlimited" mode and no "show nothing" mode, so a misconfigured
    /// 0/negative value falls back to the smallest usable cap rather than throwing on the very
    /// first <c>Show()</c> (see <see cref="EffectiveMaxToasts"/>).
    /// <para>
    /// A persistent toast (resolved <c>Duration == 0</c> — e.g. a loading/promise toast, or ANY
    /// toast that omits <c>Duration</c> under <c>DefaultDuration="0"</c>) does NOT count against
    /// this cap and is never an eviction candidate: it stays mounted until explicitly
    /// dismissed/updated, exactly like before <c>MaxToasts</c> existed. PR #357 round-4 (P2):
    /// counting persistents against the cap let one fill every slot and starve EVERY later
    /// <c>Show()</c> forever — no exit timer was ever going to free the persistent's slot, yet
    /// the overflow-queue path (below) can't tell "waiting on toasts that are actually leaving"
    /// apart from "waiting on a toast that will never leave" and queued anyway. Excluding
    /// persistents from the count sidesteps that distinction entirely: a persistent simply isn't
    /// part of the accounting, so it can occupy a mounted slot ADDITIONAL to the
    /// <c>MaxToasts</c> non-persistent ones without ever blocking them.
    /// </para>
    /// </summary>
    [Parameter] public int MaxToasts { get; set; } = 5;

    // MaxToasts <= 0 must NOT reach the raw comparisons below: with MaxToasts = 0 the eviction
    // loop's `NonPersistentMountedCount >= MaxToasts` is trivially true with an EMPTY _toasts
    // (0 >= 0), so it breaks immediately (no toast to evict) and falls through to the
    // queued-overflow path, whose own `_pendingQueue.Count >= MaxToasts` is ALSO trivially true
    // on an empty queue (0 >= 0) — calling Dequeue() on it throws InvalidOperationException on
    // the very first Show(). Clamping to a floor of 1 keeps both loops' invariants ("count >=
    // cap only once something is actually mounted/queued") intact instead of special-casing zero
    // at every call site.
    private int EffectiveMaxToasts => Math.Max(1, MaxToasts);

    // PR #357 round-6 (finding 2): "persistent" means the RESOLVED duration is 0 —
    // `options.Duration ?? DefaultDuration`, the exact expression MountToast uses to decide
    // whether to start a timer — not the raw `options.Duration == 0`. A provider configured with
    // DefaultDuration="0" makes every toast that OMITS Duration persistent too (MountToast starts
    // no timer for it), so admission must treat it identically to an explicit `Duration = 0`: never
    // counted, never evicted/queued. Checking the raw property let a default-persistent incoming
    // toast fall through to the eviction/queue path meant only for toasts that WILL eventually free
    // their own slot.
    private bool IsPersistent(ToastOptions options) => (options.Duration ?? DefaultDuration) == 0;

    // How many MOUNTED toasts count against MaxToasts within ONE position group — every toast
    // EXCEPT persistents (IsPersistent), scoped by ResolvePosition. See the MaxToasts doc
    // comment: a persistent toast can never free its own slot on its own, so it must never be
    // part of "is the cap full" accounting, or it starves every later Show() the instant enough
    // persistents accumulate to fill the cap. PR #357 round-5 (P2): MaxToasts is documented as
    // per position group but was enforced globally — a full TopLeft viewport blocked/evicted
    // against a BottomRight Show() even though the two have entirely separate, independent
    // viewports. Scoping the count (and every caller below) to a single resolved position fixes
    // that; the cap VALUE (EffectiveMaxToasts) still applies identically to every group.
    // `internal` (not `private`) is a deliberate, narrow TEST SEAM — same idiom as
    // `ExitAnimationMs` below — so invariant tests can assert the per-group cap directly off the
    // provider's own accounting instead of inferring it from rendered DOM (which can't tell a
    // persistent toast apart from a non-persistent one by markup alone).
    internal int NonPersistentMountedCount(ToastViewport.ToastPosition pos)
        => _toasts.Count(t => !IsPersistent(t.Options) && ResolvePosition(t.Options.Position) == pos);

    // PR #357 round-6 test seam: the LIVE-only (excludes toasts currently mid-exit) non-persistent
    // count for a group — `internal`, same idiom as NonPersistentMountedCount above. A toast that's
    // Leaving still counts towards NonPersistentMountedCount (that's deliberate: it keeps the RAW
    // DOM element count for the group bounded, since nothing new mounts until an eviction's exit
    // animation has ACTUALLY finished — see that method's doc comment) but has already relinquished
    // its claim on the cap the instant ReconcileGroup marked it Leaving. A toast mid-exit for its
    // OWN ~220ms animation is not a "the cap is broken" bug — sonner works the same way, and this
    // codebase already accepts that window for every ordinary eviction — so THIS is the metric
    // invariant tests should assert against, not the raw (Leaving-inclusive) one.
    internal int LiveNonPersistentMountedCount(ToastViewport.ToastPosition pos)
        => _toasts.Count(t => !IsPersistent(t.Options) && !t.Leaving && ResolvePosition(t.Options.Position) == pos);

    // Queued (never-mounted — see _pendingQueue) toasts destined for a single position group.
    // Same per-group scoping as NonPersistentMountedCount, above, so the overflow queue's own
    // cap (TryAdmit) can't let one busy position's backlog crowd out or drop a
    // completely different position's queued toasts. Persistents never reach _pendingQueue (see
    // TryAdmit), so every entry here is implicitly non-persistent already.
    private int PendingCount(ToastViewport.ToastPosition pos)
        => _pendingQueue.Count(m => ResolvePosition(m.Options.Position) == pos);

    // Removes the OLDEST still-queued entry matching predicate, preserving FIFO order for
    // everything else, and returns it (null if nothing matched). Queue<T> has no
    // remove/dequeue-by-predicate, so this rebuilds the queue minus the first match — same
    // approach as RemovePending/UpdateQueued below, generalised to an arbitrary predicate so
    // both the per-position queue cap and ReconcileGroup can share it.
    private ToastMessage? DequeueFirstMatching(Func<ToastMessage, bool> predicate)
    {
        var list = _pendingQueue.ToList();
        var idx = list.FindIndex(m => predicate(m));
        if (idx < 0) return null;
        var item = list[idx];
        list.RemoveAt(idx);
        _pendingQueue.Clear();
        foreach (var m in list) _pendingQueue.Enqueue(m);
        return item;
    }

    /// <summary>
    /// Sonner-style stacking, default on. When a position group holds more
    /// than one toast, the newest renders in front and older toasts collapse
    /// behind it with a small offset/scale, expanding to the classic list on
    /// hover or keyboard focus. Set false to always render the plain list.
    /// </summary>
    [Parameter] public bool StackToasts { get; set; } = true;

    protected override void OnInitialized()
    {
        ToastService.OnShow += HandleShow;
        ToastService.OnDismiss += HandleDismiss;
        ToastService.OnUpdate += HandleUpdate;
    }

    // Stable per-toast DOM id, derived from the toast id so it survives
    // re-renders and the JS swipe handler can target it.
    private static string ToastElementId(string toastId) => $"lumeo-toast-{toastId}";

    // After each render, attach the swipe-to-dismiss gesture to any toast
    // element that doesn't have it yet. sonner's signature gesture: dragging
    // a toast horizontally past the JS threshold dismisses it. The JS calls
    // back OnToastSwipeDismiss(toastId); we route that to the same dismissal
    // path as the close button (exit animation + OnDismiss).
    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        foreach (var toast in _toasts.ToList())
        {
            // Don't (re)register for a toast already leaving the DOM.
            if (toast.Leaving || _swipeRegistered.ContainsKey(toast.Id)) continue;

            var elementId = ToastElementId(toast.Id);
            try
            {
                await Interop.RegisterToastSwipe(elementId, toast.Id, OnToastSwiped);
                _swipeRegistered[toast.Id] = elementId;
            }
            catch (JSDisconnectedException) { }
            catch (ObjectDisposedException) { }
        }
    }

    private Task OnToastSwiped(string toastId)
    {
        // Mirror the close-button path so OnDismiss fires and the exit
        // animation plays. RemoveWithExitAsync also tears down the swipe
        // registration via CancelTimer-adjacent cleanup below.
        Remove(toastId);
        return Task.CompletedTask;
    }

    private async Task UnregisterSwipe(string toastId)
    {
        if (_swipeRegistered.TryGetValue(toastId, out var elementId))
        {
            _swipeRegistered.Remove(toastId);
            try { await Interop.UnregisterToastSwipe(toastId, elementId); }
            catch (JSDisconnectedException) { }
            catch (ObjectDisposedException) { }
        }
    }

    private void HandleShow(ToastMessage message)
    {
        SafeAsyncDispatcher.FireAndForget(InvokeAsync, () => HandleShowAsync(message), "ToastProvider.HandleShow");
    }

    private async Task HandleShowAsync(ToastMessage message) => await TryAdmit(message);

    // ══════════════════════════════════════════════════════════════════════════════════════════
    // ADMISSION MODEL (PR #357 round-6) — the ONE decision path every mutation that can affect a
    // position group's cap accounting funnels through. Two methods own ALL the invariants:
    //
    //   TryAdmit(message)   — the only entry point for a toast that has never been mounted.
    //   ReconcileGroup(pos) — the only method that evicts an over-cap mounted toast OR mounts a
    //                         queued one. Every mutation site chains STRAIGHT into calling this for
    //                         the affected group(s), with no yield (no `await`, no
    //                         `StateHasChanged()`) in between — see the field comment above for why
    //                         that ordering, not a lock, is what keeps mutation and correction
    //                         observably atomic.
    //
    // Invariants this pair maintains for every position group, at all times, including mid-burst:
    //   (a) "persistent" = resolved Duration == 0 (IsPersistent — Options.Duration ?? DefaultDuration,
    //       NOT the raw property). A provider with DefaultDuration="0" makes an omitted-Duration
    //       toast persistent too. [finding 2]
    //   (b) persistents mount directly via MountToast and NEVER touch _pendingQueue or count
    //       against NonPersistentMountedCount — never an eviction/queue participant either way.
    //   (c) mounted non-persistent count <= EffectiveMaxToasts ALWAYS, even while a burst of
    //       Show()/Update() calls races each other's evictions. TryAdmit never mounts a non-
    //       persistent toast directly — it enqueues FIRST (reserving this message's FIFO position
    //       before anything is evicted on its behalf) and only ReconcileGroup ever dequeues+mounts.
    //       That closes finding 1: the old code let the CALLER that started an eviction mount its
    //       own message directly once the await returned, but a concurrent caller's own
    //       reconciliation could already have claimed that exact freed slot for a DIFFERENT queued
    //       message by then. With every admission going through the queue, "who gets the next freed
    //       slot" has exactly one answer: whoever is FIFO-oldest in _pendingQueue at the moment
    //       ReconcileGroup's admit loop actually runs — decided fresh, every time, never assumed.
    //   (d) any state change that alters a toast's group (position) or persistence re-runs
    //       ReconcileGroup for BOTH the old and new affected groups, called immediately after the
    //       mutation with no yield in between: a queued toast whose Update retargets its position
    //       [finding 3], and a mounted toast whose Update flips its resolved persistence — most
    //       commonly a loading/promise toast resolving from persistent to finite while its group is
    //       already at/over cap [finding 4]. See HandleUpdateAsync.
    //   (e) queue admission is FIFO within a group — the admit loop always dequeues via
    //       DequeueFirstMatching, which preserves arrival order.
    //
    // Concurrency: multiple independent calls to ReconcileGroup for the SAME position CAN be in
    // flight at once (each suspended on its own eviction's ~220ms exit-animation Task.Delay) — this
    // is deliberate, not a gap: see the field comment above for why serializing them would be a
    // severe throughput regression, and why running them independently is still correct (each
    // eviction candidate is chosen via `!t.Leaving`, so two concurrent passes never pick the same
    // toast twice; each admission is a fresh dequeue at the moment it runs, never a stale decision).
    // ══════════════════════════════════════════════════════════════════════════════════════════

    private async Task TryAdmit(ToastMessage message)
    {
        // (b) — persistents bypass admission entirely: mount immediately, alongside whatever is
        // already there, never touching _pendingQueue or the eviction loop below.
        if (IsPersistent(message.Options))
        {
            MountToast(message);
            return;
        }

        var pos = ResolvePosition(message.Options.Position);

        // Cap the queue itself at MaxToasts, scoped to THIS position group (PR #357 round-5, P2).
        // Without this, a 100-toast spam burst would durably queue all ~95 overflow toasts and
        // drip them out one 220ms exit at a time (~20s to fully drain) — the opposite of "keeping
        // the newest bounded set". Dropping the oldest still-queued (never-shown) toast IN THIS
        // GROUP when a new one arrives keeps that group's known set (mounted + queued) bounded at
        // 2x MaxToasts and biases towards the most recent Show() calls, matching sonner's overflow
        // behaviour.
        if (PendingCount(pos) >= EffectiveMaxToasts)
        {
            DequeueFirstMatching(m => ResolvePosition(m.Options.Position) == pos);
        }
        // (c) — reserve this message's FIFO slot BEFORE any eviction it might need runs, then
        // reconcile IMMEDIATELY (no yield in between) — see the ADMISSION MODEL comment above for
        // why enqueue-then-reconcile (rather than evict-then-mount-directly) is what closes
        // finding 1.
        _pendingQueue.Enqueue(message);

        await ReconcileGroup(pos);
    }

    // Adds a toast to the live/mounted set and starts its auto-dismiss timer. The ONLY path that
    // appends to `_toasts` — both TryAdmit's persistent fast path and ReconcileGroup's admit loop
    // route through here, so NonPersistentMountedCount can never be pushed over MaxToasts by
    // either caller.
    private void MountToast(ToastMessage message)
    {
        _toasts.Add(new ToastItem(message.Id, message.Options));
        StateHasChanged();

        var duration = message.Options.Duration ?? DefaultDuration;
        if (duration > 0)
        {
            StartTimer(message.Id, duration);
        }
    }

    // The ONLY method that evicts an over-cap mounted toast or mounts a queued one — see the
    // ADMISSION MODEL comment above TryAdmit for the full invariant list and the field comment
    // above for why this deliberately does NOT take a lock. Every caller that can change a group's
    // cap accounting (TryAdmit, RemoveItemAsync after an actual unmount, HandleUpdateAsync after a
    // position/persistence change) calls this for the affected group(s) IMMEDIATELY after its own
    // mutation, with no yield in between, rather than mounting/evicting directly itself.
    private async Task ReconcileGroup(ToastViewport.ToastPosition pos)
    {
        // Shed down to the cap. Two distinct reasons this can be needed, both folded into one
        // condition: strictly OVER cap (finding 4 — a mounted persistent just became finite and now
        // counts, possibly pushing the group past EffectiveMaxToasts with no queue involved at
        // all), OR AT cap with queue demand waiting behind it (the ordinary "make room for a new
        // arrival" case). Evicts the oldest candidate that ISN'T already leaving — see the
        // historical spam-hang note below for why the `!t.Leaving` filter is load-bearing, not
        // cosmetic.
        //
        // PR #357 round-7 (finding 2): the condition itself is measured against
        // LiveNonPersistentMountedCount, NOT the raw (Leaving-inclusive) NonPersistentMountedCount.
        // A toast already mid-exit has already relinquished its claim on the cap the instant some
        // EARLIER reconciliation marked it Leaving (see LiveNonPersistentMountedCount's doc comment)
        // — it is going to vanish on its own without this loop's help. Measuring the raw count here
        // let a group that merely HAS a Leaving toast sitting in it look over-cap on paper even
        // though the LIVE count is within bounds: a persistent/loading toast resolving to finite
        // while an unrelated sibling in the same group is already leaving (e.g. MaxToasts=1, A
        // leaving, loading P resolves) made the raw count 2 > 1, and since the candidate query below
        // already excludes Leaving toasts (A), it evicted the live, just-resolved P instead —
        // promise/loading toasts vanishing during perfectly ordinary exit overlap. Live count keeps
        // this loop from ever treating "some toast is already on its way out" as "we're over cap and
        // must evict something else".
        while (LiveNonPersistentMountedCount(pos) > EffectiveMaxToasts ||
               (PendingCount(pos) > 0 && LiveNonPersistentMountedCount(pos) >= EffectiveMaxToasts))
        {
            var oldest = _toasts.FirstOrDefault(t =>
                !IsPersistent(t.Options) && !t.Leaving && ResolvePosition(t.Options.Position) == pos);
            if (oldest is null) break; // every remaining over-cap candidate is already Leaving —
                                        // its own removal will reconcile (ReconcileGroup) again.
            await RemoveWithExitAsync(oldest.Id, runOnDismiss: false);
        }

        // Admit queued toasts (e) FIFO while room remains. This is the ONLY place a previously-
        // queued message is ever mounted.
        while (NonPersistentMountedCount(pos) < EffectiveMaxToasts)
        {
            var next = DequeueFirstMatching(m => ResolvePosition(m.Options.Position) == pos);
            if (next is null) break;
            MountToast(next);
        }
    }

    private void HandleDismiss(string toastId)
    {
        SafeAsyncDispatcher.FireAndForget(InvokeAsync, () => HandleDismissAsync(toastId), "ToastProvider.HandleDismiss");
    }

    private async Task HandleDismissAsync(string toastId)
    {
        if (toastId == "*")
        {
            var ids = _toasts.Select(t => t.Id).ToList();
            _pendingQueue.Clear();
            await Task.WhenAll(ids.Select(id => RemoveItemAsync(id)));
        }
        else if (_pendingQueue.Any(m => m.Id == toastId))
        {
            // Dismissing a toast that's still queued (never mounted — see
            // HandleShowAsync) has nothing to animate out; just drop it so it
            // doesn't surface later once a slot frees up.
            RemovePending(toastId);
        }
        else
        {
            await RemoveItemAsync(toastId);
        }
        StateHasChanged();
    }

    // Queue<T> has no remove-by-id; rebuild preserving FIFO order minus the match.
    private void RemovePending(string toastId)
    {
        var remaining = _pendingQueue.Where(m => m.Id != toastId).ToList();
        _pendingQueue.Clear();
        foreach (var m in remaining) _pendingQueue.Enqueue(m);
    }

    // Queue<T> has no update-by-id either; rebuild preserving FIFO order, swapping in the fresh
    // options for the matching id. No-op (and no allocation beyond the Any() scan) if the id isn't
    // queued — same dedupe-by-id intent as the mounted path in HandleUpdateAsync, just for a toast
    // that hasn't been admitted into _toasts yet.
    private void UpdateQueued(string toastId, ToastOptions options)
    {
        if (!_pendingQueue.Any(m => m.Id == toastId)) return;
        var updated = _pendingQueue.Select(m => m.Id == toastId ? m with { Options = options } : m).ToList();
        _pendingQueue.Clear();
        foreach (var m in updated) _pendingQueue.Enqueue(m);
    }

    // The resolved position a still-queued (never-mounted) toast currently occupies, or null if
    // it isn't queued at all. Used by HandleUpdateAsync to capture the OLD group before an Update
    // may retarget the entry to a different one (finding 3).
    private ToastViewport.ToastPosition? PositionOfQueued(string toastId)
    {
        var msg = _pendingQueue.FirstOrDefault(m => m.Id == toastId);
        return msg is null ? null : ResolvePosition(msg.Options.Position);
    }

    private void HandleUpdate(string toastId, ToastOptions options)
    {
        SafeAsyncDispatcher.FireAndForget(InvokeAsync, () => HandleUpdateAsync(toastId, options), "ToastProvider.HandleUpdate");
    }

    private async Task HandleUpdateAsync(string toastId, ToastOptions options)
    {
        var index = _toasts.FindIndex(t => t.Id == toastId);
        if (index < 0)
        {
            // Not mounted (yet) — it may still be sitting in the overflow queue (see TryAdmit).
            // ToastService.Show already handed this id back to the caller before admission runs,
            // so Update(id, ...) can legitimately race a still-queued toast — most visibly
            // ToastService.Promise(), whose loading toast can resolve before a slot frees up.
            var oldPos = PositionOfQueued(toastId);
            if (oldPos is null) return; // not queued either — already dismissed, nothing to do.

            // PR #357 round-6 (finding 2 + 3 combined): if the update makes this entry persistent
            // (resolved Duration == 0), it no longer belongs in the cap-bounded queue at all — pull
            // it straight out and mount it directly, exactly like an incoming persistent toast
            // (TryAdmit). Left queued, it would sit waiting on a slot it will never need. Cap-
            // neutral (mounting a persistent never affects NonPersistentMountedCount), so no group
            // lock is needed for this branch — same reasoning as TryAdmit's persistent fast path.
            if (IsPersistent(options))
            {
                UpdateQueued(toastId, options);
                var promoted = DequeueFirstMatching(m => m.Id == toastId);
                if (promoted is not null) MountToast(promoted);
                return;
            }

            // (finding 3) The update may retarget this queued toast to a DIFFERENT position group
            // (e.g. queued behind a full BottomRight, updated to an empty TopLeft). Mutate FIRST,
            // then reconcile both affected groups IMMEDIATELY (no yield in between — see the
            // ADMISSION MODEL field comment for why that ordering alone keeps this atomic without
            // needing a lock): the old group's PendingCount just shrank (nothing to do there
            // usually), and the new group may have room to admit this entry right now instead of
            // waiting on an unrelated future removal that may never come for that group.
            var newPos = ResolvePosition(options.Position);
            UpdateQueued(toastId, options);
            await ReconcileGroup(oldPos.Value);
            if (newPos != oldPos.Value) await ReconcileGroup(newPos);
            return;
        }

        // (finding 4) Capture the group/persistence this MOUNTED toast counted against BEFORE
        // mutating it — a loading/promise toast most commonly goes persistent (Duration == 0) ->
        // finite (a real Duration) here, the exact transition that must re-enter cap accounting it
        // was previously exempt from. Position can change too (Update supports retargeting a
        // mounted toast's group, same as a fresh Show()).
        var wasPos = ResolvePosition(_toasts[index].Options.Position);
        var wasPersistent = IsPersistent(_toasts[index].Options);
        var isPos = ResolvePosition(options.Position);
        var isPersistent = IsPersistent(options);

        ApplyToastMutation(index, toastId, options);

        // Deliberately NOT calling StateHasChanged() here yet when a reconciliation is about to
        // run: `_toasts[index]` above already carries the NEW group/persistence, so if that change
        // pushed a group over cap, ReconcileGroup below is going to mark SOME toast Leaving as its
        // very first observable effect — chained immediately, no yield, per the ADMISSION MODEL
        // field comment. Rendering NOW, before that correction has had a chance to run, would
        // commit a frame where the over-cap state is fully visible with nothing yet marked as
        // leaving (a real bug the round-6 invariant test caught). Folding this update into
        // whichever render ReconcileGroup itself triggers (or the unconditional call below, when no
        // reconciliation is needed) means the FIRST render anyone observes after an Update already
        // reflects the fully-corrected state.
        if (wasPos != isPos || wasPersistent != isPersistent)
        {
            // Both groups' accounting may have shifted: the NEW group may now be OVER cap (a
            // persistent-turned-finite toast landing on an already-full group — finding 4's exact
            // scenario, or a MOUNTED toast retargeted into an already-full group — round-7 finding
            // 1) and need to shed back down to EffectiveMaxToasts; the OLD group may have just lost
            // a non-persistent occupant (room to admit a queued toast, or nothing to do).
            //
            // PR #357 round-7 (finding 1): the DESTINATION is reconciled FIRST, before the source.
            // `ApplyToastMutation` above already moved this toast's Options — by this point it
            // counts against `isPos`, not `wasPos` — so if `isPos` is already at cap, it is
            // OVER-cap right now and must start shedding immediately. Reconciling `wasPos` first
            // used to risk starting an UNRELATED eviction there (its own await on the ~220ms exit
            // animation, reached after `wasPos`'s own StateHasChanged), which yields control back to
            // the renderer before the over-cap destination has had any chance to correct itself —
            // committing an observable frame where the moved toast already sits in a full `isPos`
            // group with no eviction yet under way. Reconciling `isPos` first closes that window:
            // whatever correction the destination needs starts on the very next line, before
            // anything else gets a chance to yield.
            if (isPos != wasPos) await ReconcileGroup(isPos);
            await ReconcileGroup(wasPos);
        }

        // Unconditional final render: covers the (common) case where nothing needed reconciliation
        // — ReconcileGroup wouldn't have rendered anything on its own then — and is a harmless
        // no-op extra render otherwise (ReconcileGroup already committed the consistent state above).
        StateHasChanged();
    }

    // Replaces `_toasts[index]` with the updated options and resets its auto-dismiss timer. Used by
    // every HandleUpdateAsync mutated-toast path (group/persistence-changing or not) so the same
    // logic applies regardless of whether a reconciliation follows.
    private void ApplyToastMutation(int index, string toastId, ToastOptions options)
    {
        _toasts[index] = new ToastItem(toastId, options);
        CancelTimer(toastId);
        var duration = options.Duration ?? DefaultDuration;
        if (duration > 0)
        {
            StartTimer(toastId, duration);
        }
    }

    private void StartTimer(string id, int duration)
    {
        var cts = new CancellationTokenSource();
        _timers[id] = cts;
        _timerStart[id] = DateTime.UtcNow;
        _timerRemaining[id] = duration;
        SafeAsyncDispatcher.FireAndForget(InvokeAsync, () => DismissAfterDelayAsync(id, duration, cts.Token), "ToastProvider.DismissAfterDelay");
    }

    private void PauseTimer(string id)
    {
        // Don't double-pause (focusin can fire after mouseenter on the same toast).
        if (_paused.Contains(id)) return;
        if (!_timers.TryGetValue(id, out var cts)) return;
        if (!_timerStart.TryGetValue(id, out var start)) return;
        if (!_timerRemaining.TryGetValue(id, out var remaining)) return;

        var elapsed = (int)(DateTime.UtcNow - start).TotalMilliseconds;
        var left = Math.Max(0, remaining - elapsed);

        cts.Cancel();
        cts.Dispose();
        _timers.Remove(id);
        _timerRemaining[id] = left;
        _paused.Add(id);
    }

    private void ResumeTimer(string id)
    {
        if (!_paused.Contains(id)) return;
        _paused.Remove(id);
        if (!_timerRemaining.TryGetValue(id, out var remaining)) return;
        if (remaining <= 0)
        {
            // Already elapsed while paused — dismiss now.
            SafeAsyncDispatcher.FireAndForget(InvokeAsync, () => RemoveItemAsync(id), "ToastProvider.ResumeImmediateDismiss");
            return;
        }
        StartTimer(id, remaining);
    }

    private async Task DismissAfterDelayAsync(string id, int duration, CancellationToken token)
    {
        try
        {
            await Task.Delay(duration, token);
            // Use the async variant so the list removal is followed by StateHasChanged —
            // without it the toast was dropped from _toasts but never re-rendered away.
            await InvokeAsync(() => RemoveItemAsync(id));
        }
        catch (TaskCanceledException)
        {
            // Timer was cancelled — toast was manually dismissed, updated, or paused.
        }
    }

    private void InvokeAction(ToastItem toast)
    {
        toast.Options.OnAction?.Invoke();
    }

    // Exit animation duration — must match `.animate-toast-out` in lumeo.css (220 ms).
    // Internal-settable as a TEST SEAM ONLY: overlap-window tests widen it so a
    // deliberate mid-exit sequence cannot be erased by CI starvation. Production
    // code must never change it — the CSS keyframe stays 220ms.
    internal int ExitAnimationMs { get; set; } = 220;

    private void Remove(string id)
    {
        SafeAsyncDispatcher.FireAndForget(InvokeAsync, () => RemoveItemAsync(id, runOnDismiss: true), "ToastProvider.Remove");
    }

    private void RemoveItem(string id)
    {
        CancelTimer(id);
        _toasts.RemoveAll(t => t.Id == id);
    }

    // PR #357 round-6: removes a MOUNTED toast (animated exit via the raw RemoveWithExitAsync
    // primitive below) AND reconciles the group it freed a slot in — the "outer" removal path used
    // by every top-level caller (UI close/swipe via Remove, programmatic Dismiss/DismissAll,
    // auto-dismiss timers, ResumeTimer's already-elapsed-while-paused case). Deliberately NOT used
    // by ReconcileGroupCore's OWN eviction loop, which calls RemoveWithExitAsync directly — see
    // that loop's comment for why routing an eviction back through THIS method (and so back into
    // ReconcileGroup) would deadlock against the very reconciliation pass driving the eviction.
    private async Task RemoveItemAsync(string id, bool runOnDismiss = false)
    {
        var freedPos = await RemoveWithExitAsync(id, runOnDismiss);
        if (freedPos is { } pos) await ReconcileGroup(pos);
    }

    // The raw removal mechanic ONLY — marks Leaving, plays the exit animation, drops the toast
    // from `_toasts`, and returns the position group a slot just freed in (null if this was a
    // no-op: the toast wasn't found, or was already Leaving — see the idempotency guard below).
    // Deliberately does NOT itself call ReconcileGroup: every caller decides whether/how to
    // reconcile the freed slot (RemoveItemAsync does, immediately after; ReconcileGroupCore's own
    // eviction loop deliberately doesn't, since it IS the reconciliation already in progress for
    // that position — see its comment).
    private async Task<ToastViewport.ToastPosition?> RemoveWithExitAsync(string id, bool runOnDismiss)
    {
        var toast = _toasts.FirstOrDefault(t => t.Id == id);
        // Idempotent dismissal: a toast already playing its exit animation must
        // not be dismissed again. Re-entry would re-run OnDismiss, cancel the
        // in-flight exit timer (truncating the animation) and restart it.
        if (toast is null || toast.Leaving) return null;

        // PR #357 round-7 (finding 3): swap in the leaving marker SYNCHRONOUSLY, before any await
        // — including UnregisterSwipe's JS interop call below. The idempotency guard directly above
        // only protects THIS call from re-entering on a toast it already marked; it does nothing for
        // a SECOND, independent RemoveWithExitAsync call (e.g. a concurrent ReconcileGroup eviction
        // pass, or a swipe callback racing that pass) that reads `toast.Leaving` while this call is
        // still suspended on an earlier await and hasn't stamped it yet. With a real browser,
        // UnregisterSwipe awaiting JS was exactly that window: a second pass could select this SAME
        // "oldest"/candidate toast and enter its own RemoveWithExitAsync before this assignment used
        // to run, double-counting/double-evicting one toast. Capturing FrozenIndex and stamping
        // Leaving here — before CancelTimer/UnregisterSwipe/OnDismiss — means every subsequent
        // await in this method (and every OTHER concurrent caller checking `!t.Leaving`, e.g.
        // ReconcileGroup's candidate query) observes the toast as already leaving from this point
        // forward, closing that window.
        var index = _toasts.IndexOf(toast);
        if (index >= 0)
        {
            _toasts[index] = toast with { Leaving = true, FrozenIndex = ComputeStackIndex(toast) };
            StateHasChanged();
        }

        CancelTimer(id);
        // Detach the swipe gesture before the element animates out and is
        // removed; once marked Leaving it won't be re-registered.
        await UnregisterSwipe(id);
        if (runOnDismiss)
        {
            toast.Options.OnDismiss?.Invoke();
        }
        // Drop the toast after the animation would have played — the leaving marker/FrozenIndex
        // were already stamped above, before any await, per finding 3.
        if (index >= 0)
        {
            var exitCts = new CancellationTokenSource();
            _exitTimers[id] = exitCts;
            try
            {
                await Task.Delay(ExitAnimationMs, exitCts.Token);
            }
            catch (OperationCanceledException) { }
            finally
            {
                if (_exitTimers.TryGetValue(id, out var storedCts) && storedCts == exitCts)
                {
                    _exitTimers.Remove(id);
                    exitCts.Dispose();
                }
            }
        }
        // Resolve the freed slot's position group BEFORE removal — `toast` still carries its
        // original Options.Position. PR #357 round-5 (P2): reconciliation is scoped per group
        // (see ReconcileGroup's doc comment), so the caller needs to know WHICH group just gained
        // a slot.
        var freedPos = ResolvePosition(toast.Options.Position);
        _toasts.RemoveAll(t => t.Id == id);
        await InvokeAsync(StateHasChanged);
        return freedPos;
    }

    private void CancelTimer(string id)
    {
        if (_timers.TryGetValue(id, out var cts))
        {
            cts.Cancel();
            cts.Dispose();
            _timers.Remove(id);
        }
        if (_exitTimers.TryGetValue(id, out var exitCts))
        {
            exitCts.Cancel();
            exitCts.Dispose();
            _exitTimers.Remove(id);
        }
        _timerStart.Remove(id);
        _timerRemaining.Remove(id);
        _paused.Remove(id);
    }

    public async ValueTask DisposeAsync()
    {
        ToastService.OnShow -= HandleShow;
        ToastService.OnDismiss -= HandleDismiss;
        ToastService.OnUpdate -= HandleUpdate;

        foreach (var cts in _timers.Values)
        {
            cts.Cancel();
            cts.Dispose();
        }
        _timers.Clear();

        foreach (var cts in _exitTimers.Values)
        {
            cts.Cancel();
            cts.Dispose();
        }
        _exitTimers.Clear();
        _timerStart.Clear();
        _timerRemaining.Clear();
        _paused.Clear();

        // Tear down any remaining swipe gestures so the JS listeners don't leak.
        foreach (var (toastId, elementId) in _swipeRegistered.ToList())
        {
            try { await Interop.UnregisterToastSwipe(toastId, elementId); }
            catch (JSDisconnectedException) { }
            catch (ObjectDisposedException) { }
        }
        _swipeRegistered.Clear();
    }

    // FrozenIndex: the stack index this toast had the instant it started leaving
    // (stamped by RemoveWithExitAsync via ComputeStackIndex). Null while the toast
    // is still live — the render loop recomputes its index fresh every render, same
    // as always, until Leaving flips true and pins it. See the render-loop comment
    // in the markup above for why this exists (depth>=3 promotion-mid-exit flash).
    private record ToastItem(string Id, ToastOptions Options, bool Leaving = false, int? FrozenIndex = null);

    /// <summary>Resolves a per-toast <see cref="ToastPosition"/> to the
    /// <see cref="ToastViewport.ToastPosition"/> the viewport component uses,
    /// falling back to the provider's default <see cref="Position"/> when the
    /// toast didn't override. Two enums exist (one in
    /// <c>Lumeo.Services</c> for the service-facing API, one nested in
    /// <c>ToastViewport</c> for the visual component) — same members,
    /// integer-cast bridges them. (rc.42)</summary>
    private ToastViewport.ToastPosition ResolvePosition(ToastPosition? optionsPosition)
        => optionsPosition is { } p ? (ToastViewport.ToastPosition)(int)p : Position;

    // Mirrors the LIVE-ONLY/frontFrozen index math in the render-loop markup above (NOT the raw
    // groupCount - 1 - position) so RemoveWithExitAsync captures a toast's CURRENT stack index
    // the instant it starts leaving, before freezing it on the item. PR #357 round-5 (P2): this
    // previously ranked against the RAW group (every toast, including other already-frozen
    // Leaving ones), which only matches the markup's ranking while no OTHER toast in the group
    // is mid-exit. Once the front toast unmounts and a live sibling gets promoted to index 0 by
    // the markup's live-only ranking, dismissing THAT sibling while an older, stale frozen exit
    // is still in flight froze it at the raw (stale-inclusive) index instead of the live-only
    // one the markup actually rendered it at — leaving no toast frozen at index 0, so the
    // collapsed-stack CSS (which only keeps index 0 in normal flow) could collapse or jump
    // mid-overlap. `toast` here is still Leaving == false (RemoveWithExitAsync evaluates this
    // BEFORE the `with { Leaving = true, ... }` that uses its result), so it naturally counts as
    // "live" below — exactly the toast the markup's own liveCursor would be sitting on right now.
    private int? ComputeStackIndex(ToastItem toast)
    {
        if (!StackToasts) return null;
        var pos = ResolvePosition(toast.Options.Position);
        var group = _toasts.Where(t => ResolvePosition(t.Options.Position) == pos).ToList();
        var liveGroup = group.Where(t => !(t.Leaving && t.FrozenIndex.HasValue)).ToList();
        var liveCursor = liveGroup.FindIndex(t => t.Id == toast.Id);
        if (liveCursor < 0) return null;
        var frontFrozen = group.Any(t => t.Leaving && t.FrozenIndex == 0);
        return liveGroup.Count - 1 - liveCursor + (frontFrozen ? 1 : 0);
    }
}

using Microsoft.AspNetCore.Components;

namespace Lumeo;

/// <summary>
/// Partial extension to <see cref="ToastProvider"/> that adds the
/// <see cref="MaxVisible"/> stacking cap.
/// When <see cref="MaxVisible"/> &gt; 0 the provider syncs
/// <see cref="MaxToasts"/> so at most that many toasts are displayed;
/// older toasts are evicted and resurface when newer ones are dismissed.
/// </summary>
public partial class ToastProvider
{
    /// <summary>
    /// Maximum number of toasts to display simultaneously. 0 = unlimited.
    /// Older toasts beyond this cap are evicted (same behaviour as
    /// <see cref="MaxToasts"/>) and resurface when newer toasts are dismissed.
    /// </summary>
    [Parameter] public int MaxVisible { get; set; } = 0;

    protected override void OnParametersSet()
    {
        base.OnParametersSet();
        if (MaxVisible > 0)
            MaxToasts = MaxVisible;
    }
}

@namespace Lumeo

<p class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</p>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Lumeo.Cx.Merge("text-sm font-semibold [&+div]:text-xs", Class);
}

@namespace Lumeo
@implements IDisposable

@*  Sonner-style stacking (rc.??). data-stacked/data-expanded/data-stack-edge
    drive the CSS in lumeo.css's "Toast stacking" section; onmouseenter/leave
    + onfocusin/out track _hovered and _focused SEPARATELY (Expanded = hovered
    OR focused) so the group fans out to the normal list layout on hover or
    keyboard focus (focus-within) and only collapses again once BOTH are gone.
    A single shared flag would let mouseleave collapse a stack that still has
    keyboard focus inside it (e.g. tabbing through a toast's close/action
    button while the pointer happens to leave) — the toast being interacted
    with would fall back into the collapsed/absolute stack position mid-
    interaction. All logic here is per-render state — no per-frame JS, no
    .NET calls in a hot path. *@
<div class="@CssClass"
     data-stacked="@(IsStacked ? "true" : "false")"
     data-expanded="@(Expanded ? "true" : "false")"
     data-stack-edge="@StackEdge"
     @onmouseenter="@(() => _hovered = true)"
     @onmouseleave="@(() => _hovered = false)"
     @onfocusin="OnFocusIn"
     @onfocusout="OnFocusOut"
     @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter] public ToastPosition Position { get; set; } = ToastPosition.BottomRight;

    /// <summary>Whether the provider wants sonner-style stacking for this group.</summary>
    [Parameter] public bool StackToasts { get; set; } = true;

    /// <summary>Number of toasts currently rendered in this position group (including
    /// ones mid exit-animation). Stacking only kicks in above 1 toast.</summary>
    [Parameter] public int ToastCount { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Hover-anywhere-over-the-group and focus-within expansion state, tracked
    // independently so mouseleave can't collapse a stack that still has
    // keyboard focus inside it (and vice versa). Collapsed by default; the
    // CSS in lumeo.css only applies stacking transforms while
    // data-expanded="false", so Expanded=true reverts to the plain gapped list.
    private bool _hovered;
    private bool _focused;
    private bool Expanded => _hovered || _focused;

    // Keyboard focus moving BETWEEN two controls inside this group (e.g. one toast's close
    // button to another's action button) fires a bubbling focusout on the FIRST control —
    // relatedTarget is the second control, still inside this group — immediately followed by
    // focusin on that second control; both dispatch synchronously in that order. Flipping
    // `_focused = false` straight from focusout (as onfocusin/onfocusout did before) renders
    // data-expanded="false" the instant the first event lands, collapsing the stack and
    // repositioning every control mid-tab, THEN the paired focusin flips it back — a visible
    // flicker/collapse for one frame. Deferring the actual collapse by a short grace window and
    // having OnFocusIn cancel any pending one via the sequence guard means a focus move that
    // stays inside the group never flips `_focused` to false at all — only a focus move that
    // leaves the group with nothing re-claiming focus actually collapses it. Same "defer, then
    // let the next event cancel it" idiom HoverCard/MegaMenuItem use via DelayedDispatch, inlined
    // here (not the shared internal helper) so this component keeps compiling if it's ever
    // vendored on its own. NOT 0ms: a same-tick `Timer(0)` races the ThreadPool against whatever
    // dispatches the paired focusin — a genuinely async race that can (rarely but really) fire
    // the collapse before that focusin lands. A small, still-imperceptible grace window (a browser
    // tab-move's focusout->focusin pair lands within low single-digit ms) is the deterministic
    // choice instead.
    private System.Threading.Timer? _focusOutTimer;
    private int _focusOutSequence;
    private const int FocusCollapseGraceMs = 30;

    private void OnFocusIn()
    {
        _focusOutSequence++;
        _focusOutTimer?.Dispose();
        _focusOutTimer = null;
        _focused = true;
    }

    private void OnFocusOut()
    {
        var seq = ++_focusOutSequence;
        _focusOutTimer?.Dispose();
        _focusOutTimer = new System.Threading.Timer(_ =>
        {
            _ = RunSafeCollapse(seq);
        }, null, FocusCollapseGraceMs, System.Threading.Timeout.Infinite);
    }

    // PR #357 round-5 (P2): the 30ms grace timer above can fire (or already be mid-callback)
    // right as the component is torn down — navigating away, or a non-default position
    // viewport disappearing along with its last toast. Two independent guards, matching the
    // sequence-cancel + exception-swallow idiom the other local timers in this PR use
    // (Toast.razor's EnterFallbackTimer.RunSafe, ToastProvider's exit/dismiss timers):
    // Dispose() bumps `_focusOutSequence` so an in-flight callback's stale `seq` never matches
    // and mutates state post-teardown, AND this catches the disconnected-renderer exceptions
    // InvokeAsync can throw if the callback is already past that check when disposal lands.
    private async Task RunSafeCollapse(int seq)
    {
        try
        {
            await InvokeAsync(() =>
            {
                if (seq != _focusOutSequence) return; // superseded by a focusin, or disposed
                _focused = false;
                StateHasChanged();
            });
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
    }

    public void Dispose()
    {
        _focusOutSequence++; // invalidate any in-flight callback before disposing the timer
        _focusOutTimer?.Dispose();
    }

    private bool IsStacked => StackToasts && ToastCount > 1;

    private bool IsTopAnchored => Position is ToastPosition.TopLeft or ToastPosition.TopCenter or ToastPosition.TopRight;

    // The peek points AWAY from the anchored screen edge (sonner): a
    // bottom-anchored group shows the older toasts peeking out ABOVE the
    // front toast, a top-anchored group peeks out below it.
    private string StackEdge => IsTopAnchored ? "down" : "up";

    // On screens < sm (640px), every position collapses to a centered bottom strip with 16px side gutters
    // so toasts can't get cut off or have their content (title + description + close button + action) squeezed
    // to unreadable widths. From sm: up, the developer-chosen position takes effect.
    // The mobile base is bottom-anchored because that's where one-thumb reach lives on a phone.
    private string PositionClasses => Position switch
    {
        ToastPosition.TopLeft     => "fixed inset-x-4 bottom-4 sm:bottom-auto sm:end-auto sm:inset-x-auto sm:top-4 sm:start-4",
        ToastPosition.TopCenter   => "fixed inset-x-4 bottom-4 sm:bottom-auto sm:inset-x-auto sm:top-4 sm:left-1/2 sm:-translate-x-1/2",
        ToastPosition.TopRight    => "fixed inset-x-4 bottom-4 sm:bottom-auto sm:inset-x-auto sm:top-4 sm:end-4",
        ToastPosition.BottomLeft  => "fixed inset-x-4 bottom-4 sm:inset-x-auto sm:start-4",
        ToastPosition.BottomCenter => "fixed inset-x-4 bottom-4 sm:inset-x-auto sm:left-1/2 sm:-translate-x-1/2",
        _ /* BottomRight */       => "fixed inset-x-4 bottom-4 sm:inset-x-auto sm:end-4",
    };

    // Mobile: full available width (constrained by inset-x-4 = 16px gutters each side).
    // Desktop: capped at 420px so toasts don't stretch absurdly on wide monitors.
    private string CssClass => Lumeo.Cx.Merge(PositionClasses, "z-[100] flex max-h-screen w-auto sm:w-full sm:max-w-[420px] flex-col gap-2", Class);

    public enum ToastPosition { TopLeft, TopCenter, TopRight, BottomLeft, BottomCenter, BottomRight }
}
